1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string };
4	type QuoteStep = { op: "quote"; items: Item[] };
5	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
6	
7	const BASE_PRICES: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;
15	
16	const sumBasePrices = (items: Item[]): number =>
17	  items.reduce((sum, item) => sum + basePriceOf(item), 0);
18	
19	const quotePremium = (items: Item[]): number =>
20	  sumBasePrices(items) + PROCESSING_FEE;
21	
22	export const runScenario = (input: Scenario): { results: { premium: number }[] } => ({
23	  results: input.steps.map((step) => ({ premium: quotePremium(step.items) })),
24	});
